#include <stdio.h>

int calculate_turnaround_time(int submission_time, int completion_time) {
 int turnaround_time = completion_time - submission_time;
 return turnaround_time;
}

int main() {
 int submission_time = 0; // in seconds
 int completion_time = 15; // in seconds
 printf("Turnaround time: %d seconds\n", calculate_turnaround_time(submission_time, completion_time));
 return 0;
}
